export function nextGeneration(cells: Cell[]): Cell[] {
  const survivors = cells.filter((cell) => {
    const liveNeighbors = countLiveNeighbors(cell, cells);
    return liveNeighbors === 2 || liveNeighbors === 3;
  });

  const deadCandidates: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        if (cells.some(([cx, cy]) => cx === nx && cy === ny)) continue;
        if (deadCandidates.some(([cx, cy]) => cx === nx && cy === ny)) continue;
        if (countLiveNeighbors([nx, ny], cells) === 3) {
          deadCandidates.push([nx, ny]);
        }
      }
    }
  }

  return [...survivors, ...deadCandidates];
}
